window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["t"]={"Tomasz": "<b>Tomasz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aram.</a>&#160;&#8207;ܬܐܘܡܐ&#8206;, <i>tôma</i> – „bliźniak”) – imię męskie pochodzenia aramejskiego.", "Tadeusz": "<b>Tadeusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się od słowa oznaczającego „odważny”, „śmiały”. Imię przypisywane <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołowi</a> <a href=\"https://pl.wikipedia.org/wiki/Juda_Tadeusz_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Judzie</a>.", "Tymon": "<b>Tymon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „ten, który czci”, utworzone od imion złożonych typu Timótheos za pomocą sufiksu --n i usunięcie pozostałej części.", "Tymoteusz": "<b>Tymoteusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, które do polszczyzny trafiło przez łacinę. Wywodzi się od imienia Τιμόθεος (<i>Timotheos</i>), a to od słów τιμάω (<i>timao</i>) i θεός (<i>theos</i>) oznaczających „czczący boga”.", "Teodor": "W Polsce nadawane co najmniej od XIII wieku i zapisywane m.in. w postaci: <i>Tader</i>, <i>Chodor</i> (wschsł.), <i>Teodor</i>, <i>Todor</i>, <i>C(z)ader</i>, <i>C(z)eder</i>. Odpowiednikiem znaczeniowym tego imienia wśród imion staropolskich jest <a href=\"https://pl.wikipedia.org/wiki/Dadzbog\" target=\"_blank\" rel=\"noopener noreferrer\">Dadzbog</a>, <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydar</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bogdan</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bohdan</a>.", "Tobiasz": "<b>Tobiasz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia hebrajskiego, od wyrażenia <i>tobijjahu</i> oznaczającego „Bóg jest dobry”.", "Taras": "<b>Tarazjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, prawdopodobnie oznaczające \"pochodzący z Tarentum\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Tarazjusz_(patriarcha_Konstantynopola)\" target=\"_blank\" rel=\"noopener noreferrer\">Tarazjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Patriarcha_Konstantynopola\" target=\"_blank\" rel=\"noopener noreferrer\">patriarcha Konstantynopola</a>.", "Teofil": "<b>Teofil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza „miły Bogu”. Istnieją liczni święci o tym imieniu. Święty Łukasz, autor jednej z <a href=\"https://pl.wikipedia.org/wiki/Ewangelia_%C5%81ukasza\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Dzieje_Apostolskie\" target=\"_blank\" rel=\"noopener noreferrer\">Dziejów Apostolskich</a> tym imieniem (Łk 1,3) (Dz 1,1) zwraca się do swojego czytelnika rozpoczynając napisane przez siebie księgi.", "Tytus": "<b>Tytus</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do nielicznej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Marek</a>, <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Kwintus\" target=\"_blank\" rel=\"noopener noreferrer\">Kwintus</a>). <i>Titus</i> oznacza „dziki gołąb”; słowo to miało jednakże w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnym Rzymie</a> znaczenie przenośne i było stosowane także dla oznaczenia <a href=\"https://pl.wikipedia.org/wiki/M%C4%99ski_uk%C5%82ad_p%C5%82ciowy\" target=\"_blank\" rel=\"noopener noreferrer\">męskości</a>.", "Tristan": "Był rycerzem <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3l_Marek\" target=\"_blank\" rel=\"noopener noreferrer\">króla Marka</a>, władcy <a href=\"https://pl.wikipedia.org/wiki/Kornwalia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornwalii</a>. Pochodził z <a href=\"https://pl.wikipedia.org/wiki/Lyonesse\" target=\"_blank\" rel=\"noopener noreferrer\">Lonii</a>. Jego matką była Blancheflor (lub też Isabelle), a ojcem Riwalen. Był siostrzeńcem lub – w innych wersjach – bratankiem króla Marka. Był też rycerzem Okrągłego Stołu, po zabiciu <a href=\"https://pl.wikipedia.org/wiki/Morho%C5%82t\" target=\"_blank\" rel=\"noopener noreferrer\">Morhołta</a> (wuja Izoldy). Zobowiązał się przywieźć królowi Markowi jego wybrankę, irlandzką księżniczkę, <a href=\"https://pl.wikipedia.org/wiki/Izolda_Jasnow%C5%82osa\" target=\"_blank\" rel=\"noopener noreferrer\">Izoldę Jasnowłosą</a>. Młodzi, nieświadomie wypiwszy <a href=\"https://pl.wikipedia.org/wiki/Nap%C3%B3j_mi%C5%82osny\" target=\"_blank\" rel=\"noopener noreferrer\">napój miłosny</a> w trakcie podróży morskiej do Kornwalii, nieszczęśliwie się w sobie zakochali.", "Tycjan": "Od imienia artysty wywodzi się słowo <i>tycjanowski</i> używane na określenie koloru <a href=\"https://pl.wikipedia.org/wiki/Barwa_pomara%C5%84czowa\" target=\"_blank\" rel=\"noopener noreferrer\">rudopomarańczowego</a>, często wykorzystywanego w obrazach.", "Theodor": "W Polsce nadawane co najmniej od XIII wieku i zapisywane m.in. w postaci: <i>Tader</i>, <i>Chodor</i> (wschsł.), <i>Teodor</i>, <i>Todor</i>, <i>C(z)ader</i>, <i>C(z)eder</i>. Odpowiednikiem znaczeniowym tego imienia wśród imion staropolskich jest <a href=\"https://pl.wikipedia.org/wiki/Dadzbog\" target=\"_blank\" rel=\"noopener noreferrer\">Dadzbog</a>, <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydar</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bogdan</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bohdan</a>.", "Telesfor": "<b>Telesfor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, gr. <i>Τελεσφορος (Telesphóros)</i>, oznaczające „doprowadzony do końca, doprowadzony do doskonałości”.", "Tudor": "Protoplastami tej dynastii byli Owen Tudor (<a href=\"https://pl.wikipedia.org/wiki/Walia\" target=\"_blank\" rel=\"noopener noreferrer\">Walijczyk</a> – jego właściwe imię brzmiało: <i>Owain ap Maredudd ap Tudur</i>) – potomek Ednyfeda Fychana, oraz <a href=\"https://pl.wikipedia.org/wiki/Katarzyna_de_Valois\" target=\"_blank\" rel=\"noopener noreferrer\">Katarzyna de Valois</a> (córka króla <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a> – <a href=\"https://pl.wikipedia.org/wiki/Karol_VI_Szalony\" target=\"_blank\" rel=\"noopener noreferrer\">Karola VI Szalonego</a>), <a href=\"https://pl.wikipedia.org/wiki/Angielskie_kr%C3%B3lowe\" target=\"_blank\" rel=\"noopener noreferrer\">królowa Anglii</a> – wdowa po <a href=\"https://pl.wikipedia.org/wiki/Henryk_V_Lancaster\" target=\"_blank\" rel=\"noopener noreferrer\">Henryku V</a>. Po śmierci Henryka V zawarli oni sekretne małżeństwo i mieli trzech synów – <a href=\"https://pl.wikipedia.org/wiki/Edmund_Tudor_(hrabia_Richmond)\" target=\"_blank\" rel=\"noopener noreferrer\">Edmunda</a>, <a href=\"https://pl.wikipedia.org/wiki/Jasper_Tudor\" target=\"_blank\" rel=\"noopener noreferrer\">Jaspera</a> i Owena oraz córki (źródła różnią się co do ich liczby).", "Tuan": "Opowieść o Tuanie pochodzi z iryjskiego dzieła <i>Leabhar Gabala</i>.", "Tarik": "Od jego imienia pochodzi nazwa <a href=\"https://pl.wikipedia.org/wiki/Gibraltar\" target=\"_blank\" rel=\"noopener noreferrer\">Gibraltar</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <i>Dżabal Tarik</i> — Góra Tarika).", "Tomek": "<b>Tomasz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aram.</a>&#160;&#8207;ܬܐܘܡܐ&#8206;, <i>tôma</i> – „bliźniak”) – imię męskie pochodzenia aramejskiego.", "Tomir": "<b>Tomir</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, nienotowane w źródłach staropolskich, złożone z członów <i>To-</i> i <i>-mir</i>. Żeński odpowiednik: <a href=\"https://pl.wikipedia.org/wiki/Tomira\" target=\"_blank\" rel=\"noopener noreferrer\">Tomira</a>.", "Tomisław": "<b>Tomisław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie, złożone z członów <i>Tomi-</i> (<i>tomiti</i> – \"dręczyć, męczyć\") i <i>-sław</i> (\"sława\"). Mogło oznaczać np. \"tego, którego dręczy potrzeba sławy\", \"tego, który jest udręczony sławą\" lub \"ten, który dręczy innych swą sławą\". Żeński odpowiednik: <a href=\"https://pl.wikipedia.org/wiki/Tomis%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Tomisława</a>.", "Tamir": "<b>Tamir Airways</b> – prywatna <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">izraelska</a> <a href=\"https://pl.wikipedia.org/wiki/Linia_lotnicza\" target=\"_blank\" rel=\"noopener noreferrer\">linia lotnicza</a> (<a href=\"https://pl.wikipedia.org/wiki/Kod_linii_ICAO\" target=\"_blank\" rel=\"noopener noreferrer\">kod linii ICAO</a>: TMI), oferująca krajowe połączenia pasażerskie oraz <a href=\"https://pl.wikipedia.org/wiki/Czarter\" target=\"_blank\" rel=\"noopener noreferrer\">czarterowe</a> w Izraelu. Głównym portem lotniczym jest <a href=\"https://pl.wikipedia.org/wiki/Port_lotniczy_Ben_Guriona_w_Tel_Awiwie\" target=\"_blank\" rel=\"noopener noreferrer\">międzynarodowe lotnisko imienia Ben Guriona</a> w <a href=\"https://pl.wikipedia.org/wiki/Tel_Awiw-Jafa\" target=\"_blank\" rel=\"noopener noreferrer\">Tel Awiwie</a>.", "Thor": "Od jego imienia pochodzi nazwa <a href=\"https://pl.wikipedia.org/wiki/Czwartek\" target=\"_blank\" rel=\"noopener noreferrer\">czwartku</a> (jako „dzień Thora”) w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_du%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języku duńskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_norweski\" target=\"_blank\" rel=\"noopener noreferrer\">norweskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_szwedzki\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkim</a> (<i>torsdag</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_farerski\" target=\"_blank\" rel=\"noopener noreferrer\">farerskim</a> (<i>hósdagur</i>/<i>tórsdagur</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_fi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">fińskim</a> (<i>torstai</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niderlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">niderlandzkim</a> (<i>donderdag</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a> (<i>Donnerstag</i>) oraz <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskim</a> (<i>Þunresdæg</i>) i współczesnym <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskim</a> (<i>Thursday</i>).", "Trojan": "<b>Trojan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, którego patronem jest św. Trojan, uczeń św. Bibiana, biskup <a href=\"https://pl.wikipedia.org/wiki/Saintes\" target=\"_blank\" rel=\"noopener noreferrer\">Saintes</a>.", "Takashi": "<b>Takashi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;たかし, タケシ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Tendai": "<b>Tendai</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;天台宗&#32;<i>Tendai-shū</i>) – <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">japońska</a> szkoła buddyjska założona przez <a href=\"https://pl.wikipedia.org/wiki/Saich%C5%8D\" target=\"_blank\" rel=\"noopener noreferrer\">Saichō</a> w <a href=\"https://pl.wikipedia.org/wiki/805\" target=\"_blank\" rel=\"noopener noreferrer\">805</a> roku. Szkoła wywodzi się z chińskiej szkoły buddyzmu <a href=\"https://pl.wikipedia.org/wiki/Mahajana\" target=\"_blank\" rel=\"noopener noreferrer\">mahajany</a> - <a href=\"https://pl.wikipedia.org/wiki/Tiantai\" target=\"_blank\" rel=\"noopener noreferrer\">tiantai</a> - zwanej też <b>Szkołą Sutry Lotosu</b>. W <a href=\"https://pl.wikipedia.org/wiki/822\" target=\"_blank\" rel=\"noopener noreferrer\">822</a> roku nadano klasztorowi Tendai prawa niezależnej ordynacji na górze Hiei.", "Teodoro": "Najstarsze wzmianki o księstwie Teodoro i jego ówczesnym władcy <a href=\"https://pl.wikipedia.org/wiki/Demetriusz_Gabras\" target=\"_blank\" rel=\"noopener noreferrer\">Demetriosie</a> pochodzą z 1362 (inskrypcja) i z 1363, przy czym mówi się w nich o już istniejącym księstwie i biorącym udział w walkach, dlatego sam organizm państwowy musiał powstać trochę wcześniej. Do niedawna uważano, że założycielem państwa był miejscowy ormiański ród <a href=\"https://pl.wikipedia.org/wiki/Gabrasowie\" target=\"_blank\" rel=\"noopener noreferrer\">Gabrasów</a>, jednak w 2001 przedstawiono dowody, że w istocie pierwszymi władcami byli przedstawiciele krymskiej ludności bizantyjskiej. Panującą religią było <a href=\"https://pl.wikipedia.org/wiki/Prawos%C5%82awie\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławie</a>, językiem państwa był <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">język grecki</a>, a początkową nazwą <i>Teodoro-Mangup</i>. Pod koniec XIV w. wojska <a href=\"https://pl.wikipedia.org/wiki/Timur_Chromy\" target=\"_blank\" rel=\"noopener noreferrer\">Tamerlana</a> zniszczyły większość Krymu, w tym i Teodoro. W następnych latach jeden z czołowych władców w historii Teodoro, książę <a href=\"https://pl.wikipedia.org/wiki/Aleksy_I_Gabras\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksy I Gabras</a> dokończył odbudowę zrujnowanego państwa i zaczął ekspansję terytorialną, co doprowadziło do wojen z <a href=\"https://pl.wikipedia.org/wiki/Genua\" target=\"_blank\" rel=\"noopener noreferrer\">genueńską</a> wówczas <a href=\"https://pl.wikipedia.org/wiki/Teodozja_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Kaffą</a> w okresie 1422–1424 i 1433–1441, toczonych ze zmiennym szczęściem i zakończonych bez istotnych nabytków lub strat terytorialnych obu stron. Pod koniec maja 1475 na Krym przybyła armia i flota <a href=\"https://pl.wikipedia.org/wiki/Imperium_Osma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">turecka</a>, którą dowodził <a href=\"https://pl.wikipedia.org/wiki/Gedik_Ahmed_Pasza\" target=\"_blank\" rel=\"noopener noreferrer\">Gedik Ahmed Pasza</a>. Turcy zdobyli Kaffę i inne włoskie posiadłości na Krymie, a następnie przez pół roku bez skutku oblegali Mangup. Dopiero w grudniu tego roku, oblegające wojska zdołały podstępem wedrzeć się do miasta, dokonać rzezi jego mieszkańców i zlikwidować zarówno panujący ród, jak i samo księstwo.", "Teodozjusz": "<b>Teodozjusz</b>, <b>Teodozy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Ma znaczenie analogiczne do imienia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>, a oznacza \"dany od Boga\".", "Takeshi": "<b>Takeshi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;たけし, タケシ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Teobald": "<b>Teobald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, zapisywane w Polsce od średniowiecza. Pierwszy człon to germ. <i>þeudo</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>thioda</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>diot</i> – „lud”; drugi to <i>bald</i> – „odważny, śmiały”. Można je tłumaczyć jako „sławny wśród ludzi”. Pierwszy człon tego imienia notował liczne odmiany, w tym w dawnej Polsce zapisano wariant tego imienia <b>Tybald</b> (tę formę imienia przyjęto w tłumaczeniu dla <a href=\"https://pl.wikipedia.org/wiki/Tybalt\" target=\"_blank\" rel=\"noopener noreferrer\">jednej z postaci</a> „<a href=\"https://pl.wikipedia.org/wiki/Romeo_i_Julia\" target=\"_blank\" rel=\"noopener noreferrer\">Romea i Julii</a>” <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Szekspira</a>), <b>Dypołt</b>, <b>Dziepołt</b>. Forma z początkowym <i>Teo-</i> &lt; germ. <i>Theudo-</i> jest <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">zhellenizowana</a> z odniesieniem do gr. <i>θεος (theos)</i> – „bóg”; notowana w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku (natomiast forma Dziepołt – <i>Depoldus</i> – od <a href=\"https://pl.wikipedia.org/wiki/1218\" target=\"_blank\" rel=\"noopener noreferrer\">1218</a> roku).", "Trofim": "<b>Trofim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> wyrazu <i>tróphimos</i>, oznaczające „żywiący, pożywny”. Żyło kilku <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty\" target=\"_blank\" rel=\"noopener noreferrer\">świętych</a> o tym imieniu. Dawniej było ono częściej nadawane na obszarze działania <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bcio%C5%82y_wschodnie\" target=\"_blank\" rel=\"noopener noreferrer\">Kościoła wschodniego</a>, niż <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościoła katolickiego</a>.", "Tara": "<b>Tara</b> – imię żeńskie wywodzące się z różnych kultur.", "Tarsycjusz": "<b>Tarsycjusz, Tarzycjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od greckiego słowa <i>Tarsisi,</i> nazwy starożytnego greckiego miasta Tarsos. Nazwa ta była zhellenizowaną formą <a href=\"https://pl.wikipedia.org/wiki/Tarsus_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Tarsu</a>. Możliwe jest także etruskie pochodzenie tego imienia.", "Tolisław": "<b>Tolisław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członów <i>Toli-</i> (<i>toliti</i> – \"uspokajać\", też: \"tulić\"), i <i>-sław</i> (\"sława\"). Znaczenie imienia: \"wyciszający sławę\", \"skromny\". Żeński odpowiednik – <a href=\"https://pl.wikipedia.org/wiki/Tolis%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Tolisława</a>.", "Takahiro": "<b>Takahiro</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;たかひろ, タカヒロ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Tadek": "<b>Tadek</b>, właśc. <b>Tadeusz Polkowski</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/26_sierpnia\" target=\"_blank\" rel=\"noopener noreferrer\">26 sierpnia</a> <a href=\"https://pl.wikipedia.org/wiki/1982\" target=\"_blank\" rel=\"noopener noreferrer\">1982</a> w <a href=\"https://pl.wikipedia.org/wiki/Krak%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Krakowie</a>) – <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">polski</a> raper. Znany jest przede wszystkim z wieloletnich występów w zespole hip-hopowym <a href=\"https://pl.wikipedia.org/wiki/Firma_(zesp%C3%B3%C5%82_muzyczny)\" target=\"_blank\" rel=\"noopener noreferrer\">Firma</a>, którego był współzałożycielem. Wcześniej występował w lokalnej formacji DMF (Dwóch Małoletnich Fachowców). Od 2011 prowadzi również solową działalność artystyczną.", "Teodozy": "<b>Teodozjusz</b>, <b>Teodozy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Ma znaczenie analogiczne do imienia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>, a oznacza \"dany od Boga\".", "Tarcyzjusz": "<b>Tarsycjusz, Tarzycjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od greckiego słowa <i>Tarsisi,</i> nazwy starożytnego greckiego miasta Tarsos. Nazwa ta była zhellenizowaną formą <a href=\"https://pl.wikipedia.org/wiki/Tarsus_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Tarsu</a>. Możliwe jest także etruskie pochodzenie tego imienia.", "Ting": "W krajach <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskich</a> pochodzą od nich nazwy parlamentów:", "Tatsuya": "<b>Tatsuya</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;たつや, タツヤ) – popularne męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Takuya": "<b>Takuya</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;たくや, タクヤ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Tsutomu": "<b>Tsutomu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;つとむ, ツトム) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Tomił": "<b>Tomił</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, nienotowane w źródłach staropolskich, złożone z członów <i>To-</i> i <i>-mił</i>. Żeński odpowiednik: <a href=\"https://pl.wikipedia.org/wiki/Tomi%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">Tomiła</a>.", "Tetsuya": "<b>Tetsuya</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;てつや, テツヤ) – popularne męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Tirtha": "Terminem \"tirtha\" oznacza się również siedem świętych miejsc w <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indiach</a>. Są to: <a href=\"https://pl.wikipedia.org/wiki/Ayodhya\" target=\"_blank\" rel=\"noopener noreferrer\">Ayodhya</a>, <a href=\"https://pl.wikipedia.org/wiki/Mathura\" target=\"_blank\" rel=\"noopener noreferrer\">Mathura</a>, <a href=\"https://pl.wikipedia.org/wiki/Gaja_(Bihar)\" target=\"_blank\" rel=\"noopener noreferrer\">Gaya</a>, <a href=\"https://pl.wikipedia.org/wiki/Waranasi\" target=\"_blank\" rel=\"noopener noreferrer\">Kaśi</a>, <a href=\"https://pl.wikipedia.org/wiki/Kanchipuram\" target=\"_blank\" rel=\"noopener noreferrer\">Kanchipuram</a>, Avantika (<a href=\"https://pl.wikipedia.org/wiki/Ujjain\" target=\"_blank\" rel=\"noopener noreferrer\">Ujjain</a>) i <a href=\"https://pl.wikipedia.org/wiki/Dwarawati\" target=\"_blank\" rel=\"noopener noreferrer\">Dwarawati</a>.", "Tian": "Słowo <i>Tiān</i> oznacza <i>Niebiosa</i>, <i>Niebo</i>, <i>Bóg</i>, <i>Bogowie</i>. W chińskiej filozofii Niebo było pierwiastkiem męskim, symbolizującym <a href=\"https://pl.wikipedia.org/wiki/Yin_i_yang\" target=\"_blank\" rel=\"noopener noreferrer\">yang</a>, w opozycji do symbolizującej yin Ziemi. W tradycyjnej chińskiej religii Niebo postrzegane było jako mieszkanie bogów. Niebo było także postrzegane jako osobowy, najwyższy bóg, czczony pod imieniem <a href=\"https://pl.wikipedia.org/wiki/Shangdi\" target=\"_blank\" rel=\"noopener noreferrer\">Shangdi</a>. Niebiosa otoczone były w Chinach wielkim szacunkiem, upersonifikowane stanowiły stwórcę wszechrzeczy.", "Turki": "Według legendy funkcjonująca w tych regionach nazwa straży grobowych wywodzi się z czasów <a href=\"https://pl.wikipedia.org/wiki/Bitwa_pod_Wiedniem\" target=\"_blank\" rel=\"noopener noreferrer\">odsieczy wiedeńskiej</a>. Powracający z wojny <a href=\"https://pl.wikipedia.org/wiki/Ch%C5%82opi\" target=\"_blank\" rel=\"noopener noreferrer\">chłopi</a> ubrani byli w zdobyczne stroje <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">tureckie</a> i przybywali do rodzinnych wsi w <a href=\"https://pl.wikipedia.org/wiki/Wielki_Pi%C4%85tek\" target=\"_blank\" rel=\"noopener noreferrer\">Wielki Piątek</a>, <a href=\"https://pl.wikipedia.org/wiki/Wielka_Sobota\" target=\"_blank\" rel=\"noopener noreferrer\">Wielką Sobotę</a> lub <a href=\"https://pl.wikipedia.org/wiki/Wielkanoc\" target=\"_blank\" rel=\"noopener noreferrer\">Wielką Niedzielę</a>, udając się bezpośrednio do <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_(budynek)\" target=\"_blank\" rel=\"noopener noreferrer\">kościoła</a> i zaciągając <a href=\"https://pl.wikipedia.org/wiki/Warta_(wojsko)\" target=\"_blank\" rel=\"noopener noreferrer\">wartę</a> przy Grobie Pańskim.", "Tezeusz": "Uchodził za syna <a href=\"https://pl.wikipedia.org/wiki/Posejdon\" target=\"_blank\" rel=\"noopener noreferrer\">Posejdona</a> i <a href=\"https://pl.wikipedia.org/wiki/Ajtra_(c%C3%B3rka_Pitteusa)\" target=\"_blank\" rel=\"noopener noreferrer\">Ajtry</a> (formalnie był synem <a href=\"https://pl.wikipedia.org/wiki/Egeusz\" target=\"_blank\" rel=\"noopener noreferrer\">Egeusza</a>, króla <a href=\"https://pl.wikipedia.org/wiki/Ateny\" target=\"_blank\" rel=\"noopener noreferrer\">Aten</a>). Wychowywany poza domem z obawy przed żądnymi tronu synami swojego stryja <a href=\"https://pl.wikipedia.org/wiki/Pallas_(syn_Pandiona)\" target=\"_blank\" rel=\"noopener noreferrer\">Pallasa</a>. Jego wejściem w dorosłość było uniesienie głazu, pod którym Egeusz (Ajgeus) zostawił dla niego miecz i sandały.", "Telemach": "Urodził się tuż przed rozpoczęciem <a href=\"https://pl.wikipedia.org/wiki/Wojna_troja%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">wojny trojańskiej</a>. Jeszcze jako dziecko wpadł do morza, uratowały go delfiny. Dlatego Odyseusz miał na tarczy delfina. Razem z matką czekał 20 lat na powrót ojca. W czasie nieobecności Odyseusza opiekował się nim zaufany przyjaciel ojca <a href=\"https://pl.wikipedia.org/wiki/Mentor_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mentor</a>. Kiedy Telemach dorósł, postanowił wyruszyć w podróż, w poszukiwaniu informacji o ojcu. Zalotnicy jego matki wysłali okręt, który miał zniszczyć statek Telemacha. Telemach kazał popłynąć inną drogą, dzięki temu uratował siebie i całą załogę. Odwiedził <a href=\"https://pl.wikipedia.org/wiki/Menelaos\" target=\"_blank\" rel=\"noopener noreferrer\">Menelaosa</a> i <a href=\"https://pl.wikipedia.org/wiki/Nestor_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Nestora</a>. Podczas odwiedzin u Nestora przyjęła go Polykasta, córka Nestora. Istnieją przekazy, że miał z nią dwoje dzieci - Persepolisa i Homera.", "Tychon": "<b>Tychon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od Τύχων (por. <a href=\"https://pl.wikipedia.org/wiki/Tyche\" target=\"_blank\" rel=\"noopener noreferrer\">Tyche</a>). Jego patronem jest biskup <a href=\"https://pl.wikipedia.org/wiki/Cypr_(wyspa)\" target=\"_blank\" rel=\"noopener noreferrer\">Cypru</a> <a href=\"https://pl.wikipedia.org/wiki/Tychon_(biskup_Amathus)\" target=\"_blank\" rel=\"noopener noreferrer\">Tychon (biskup Amathus)</a> <a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV</a>/<a href=\"https://pl.wikipedia.org/wiki/V_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">V wieku</a>.", "Tuliusz": "<b>Tuliusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od rzymskiej nazwy rodowej prawdopodobnie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_etruski\" target=\"_blank\" rel=\"noopener noreferrer\">etruskiego</a>. Patronem tego imienia jest św. Tuliusz, zm. w Afryce w <a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wieku</a>.", "Tetsuo": "<b>Tetsuo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;てつお, テツオ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Taichi": "<b>Taichi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;たいち, タイチ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Trinidad": "<b>Trinidad</b> – jest żeńskim imieniem hiszpańskim, w języku hiszpańskim oznacza <i>Trójca</i> co stanowi nawiązanie do <a href=\"https://pl.wikipedia.org/wiki/Tr%C3%B3jca_%C5%9Awi%C4%99ta\" target=\"_blank\" rel=\"noopener noreferrer\">Trójcy Świętej</a>.", "Tsuyoshi": "<b>Tsuyoshi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;つよし, ツヨシ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Timmy": "Nazwa „Timmy” pochodzi od miejscowości <a href=\"https://pl.wikipedia.org/wiki/Timmendorfer_Strand\" target=\"_blank\" rel=\"noopener noreferrer\">Timmendorfer Strand</a>.", "Tapas": "Pochodzenie <i>tapas</i> wiąże się z tym, że Andaluzyjczycy pijąc <a href=\"https://pl.wikipedia.org/wiki/Wino\" target=\"_blank\" rel=\"noopener noreferrer\">wino</a>, szklankę przykrywali plasterkiem suchej kiełbasy, aby chronić ją przed muchami. Z czasem zaczęto dodawać cienką kromkę chleba z różnymi dodatkami. Do najbardziej znanych <i>tapas</i> należą:", "Takeo": "<b>Takeo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;たけお, タケオ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Teodoryk": "<b>Teodoryk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, zapisywane w Polsce od średniowiecza. Poza zbliżonym brzmieniem, nie ma ono wiele wspólnego z imieniem <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>.", "Takeru": "<b>Takeru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;たける, タケル) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Takuma": "<b>Takuma</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;たくま, タクマ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Tales": "Wiedza o Talesie pochodzi z przekazów późniejszych: wiadomości o jego życiu są skąpe, mają w dużej mierze charakter tradycji o charakterze anegdotycznym; wiadomości o jego myśli filozoficznej przekazał przede wszystkim <a href=\"https://pl.wikipedia.org/wiki/Arystoteles\" target=\"_blank\" rel=\"noopener noreferrer\">Arystoteles</a>, są one jednak w dużym stopniu anachroniczne i odkształcone. Wśród Greków znany był zresztą głównie z działalności praktycznej i politycznej – m.in. miał przewidzieć zaćmienie słońca (28 maja 585 p.n.e.). Tales wykorzystał przy tym wiadomości astronomiczne o periodycznej powtarzalności (cykliczności) zaćmień, wiadomości, które zdobył w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a> lub w <a href=\"https://pl.wikipedia.org/wiki/Fenicja\" target=\"_blank\" rel=\"noopener noreferrer\">Fenicji</a>. Miał także skłaniać Jonów do zawarcia unii politycznej, współdziałać z <a href=\"https://pl.wikipedia.org/wiki/Krezus\" target=\"_blank\" rel=\"noopener noreferrer\">Krezusem</a>, odwrócić bieg rzeki <a href=\"https://pl.wikipedia.org/wiki/K%C4%B1z%C4%B1l%C4%B1rmak\" target=\"_blank\" rel=\"noopener noreferrer\">Halys</a> i obliczyć wysokość piramidy (tzw. „<a href=\"https://pl.wikipedia.org/wiki/Twierdzenie_Talesa\" target=\"_blank\" rel=\"noopener noreferrer\">twierdzenie Talesa</a>”).", "Tryfon": "<b>Tryfon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od greckiego <i>τρυφη (tryfe)</i>, co oznacza \"miękkość, łagodność\". Wśród świętych – św. <a href=\"https://pl.wikipedia.org/wiki/Tryfon_(m%C4%99czennik)\" target=\"_blank\" rel=\"noopener noreferrer\">Tryfon</a>, męczennik (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Teofan": "<b>Teofan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Θεοφάνης), oznaczające „przejawienie się Boga” — złożone z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;θεός (<i>theos</i>, „bóg”) i φανης (<i>phanes</i>, „objawić się, ukazać się”). Imię to notowane jest w źródłach polskich (na Śląsku, w Wielkopolsce i na Mazowszu) od <a href=\"https://pl.wikipedia.org/wiki/XIV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIV wieku</a>, w formie <b>Tyfan</b>. Świętych, noszących to imię, było co najmniej sześciu.", "Taifun": "Koncepcja Taifuna powstała latem 1944 roku z inicjatywy inż. Klausa Scheufelena na podstawie teoretycznych analiz skuteczności <a href=\"https://pl.wikipedia.org/wiki/Artyleria_przeciwlotnicza\" target=\"_blank\" rel=\"noopener noreferrer\">artylerii przeciwlotniczej</a>. Pocisk przeznaczony był do zwalczania formacji bombowców strategicznych na dużych pułapach (10–12 km). Odpalany miał być w salwach po kilkadziesiąt sztuk i wyposażony w <a href=\"https://pl.wikipedia.org/wiki/Zapalnik_uderzeniowy\" target=\"_blank\" rel=\"noopener noreferrer\">zapalnik uderzeniowy</a> zamiast zwykle stosowanego w ciężkiej artylerii przeciwlotniczej zapalnika czasowego. Rozwiązanie takie pozwalało na znaczne zminimalizowanie ilości <a href=\"https://pl.wikipedia.org/wiki/Materia%C5%82_wybuchowy\" target=\"_blank\" rel=\"noopener noreferrer\">materiału wybuchowego</a> w <a href=\"https://pl.wikipedia.org/wiki/G%C5%82owica_bojowa\" target=\"_blank\" rel=\"noopener noreferrer\">głowicy bojowej</a>, przy oczekiwanym statystycznym wzroście prawdopodobieństwa zestrzelenia bombowca. Projekt zatwierdzony został przez Ministerstwo Lotnictwa Rzeszy (RLM) w październiku, a produkcja seryjna ulokowana została w podziemnej fabryce zbrojeniowej <a href=\"https://pl.wikipedia.org/wiki/Mittelwerk\" target=\"_blank\" rel=\"noopener noreferrer\">Mittelwerk</a> w <a href=\"https://pl.wikipedia.org/wiki/Harz\" target=\"_blank\" rel=\"noopener noreferrer\">Harzu</a>.", "Tamal": "<b>Tamal</b>, l. mn. tamales, z języka <a href=\"https://pl.wikipedia.org/wiki/Nahuatl\" target=\"_blank\" rel=\"noopener noreferrer\">nahuatl</a> <i>tamalli</i> (dosłownie „zawinięty”) – danie <a href=\"https://pl.wikipedia.org/wiki/Meksyk\" target=\"_blank\" rel=\"noopener noreferrer\">meksykańskie</a> pochodzenia przedkolumbijskiego (jadano je już około 5-8 tysięcy lat temu), składające się z nadziewanego <a href=\"https://pl.wikipedia.org/wiki/Ciasto\" target=\"_blank\" rel=\"noopener noreferrer\">ciasta</a> z <a href=\"https://pl.wikipedia.org/wiki/M%C4%85ka_kukurydziana\" target=\"_blank\" rel=\"noopener noreferrer\">mąki kukurydzianej</a>, <a href=\"https://pl.wikipedia.org/wiki/Gotowanie_na_parze\" target=\"_blank\" rel=\"noopener noreferrer\">gotowane na parze</a> po uprzednim owinięciu liściem z <a href=\"https://pl.wikipedia.org/wiki/Kolba_(botanika)\" target=\"_blank\" rel=\"noopener noreferrer\">kolby</a> kukurydzy (czasami również innymi liśćmi). Istnieje wiele różnych wersji smakowych, na ostro, na słodko, z <a href=\"https://pl.wikipedia.org/wiki/Farsz\" target=\"_blank\" rel=\"noopener noreferrer\">farszem</a> mięsnym (<a href=\"https://pl.wikipedia.org/wiki/Wieprzowina\" target=\"_blank\" rel=\"noopener noreferrer\">wieprzowina</a>, <a href=\"https://pl.wikipedia.org/wiki/Wo%C5%82owina\" target=\"_blank\" rel=\"noopener noreferrer\">wołowina</a>, kurczak) lub <a href=\"https://pl.wikipedia.org/wiki/Ser\" target=\"_blank\" rel=\"noopener noreferrer\">serowym</a>. Potrawa ta jest popularna również w <a href=\"https://pl.wikipedia.org/wiki/Peru\" target=\"_blank\" rel=\"noopener noreferrer\">Peru</a> i innych krajach <a href=\"https://pl.wikipedia.org/wiki/Ameryka_%C5%81aci%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Łacińskiej</a>. Podawana jest z <a href=\"https://pl.wikipedia.org/wiki/Salsa_(potrawa)\" target=\"_blank\" rel=\"noopener noreferrer\">salsą</a>, często dostępna na ulicznych stoiskach, a najpopularniejsza w okresie <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">bożonarodzeniowym</a>.", "Tsubasa": "<b>Tsubasa</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;つばさ, ツバサ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez mężczyzn, jak i przez kobiety.", "Tankred": "<b>Tankred</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>tank</i> – myśl oraz <i>rad</i> – rada, zebranie\".", "Toshio": "<b>Toshio</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;としお, トシオ) – popularne męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Tacjan": "<b>Tacjan</b> – imię męskie powstałe z rzymskiego przydomka <i>Tatianus</i>, pochodzącego od rodu <i>Tacii</i> (pol. Tacjusze).", "Tusi": "<b>Tusi</b> (<a href=\"https://pl.wikipedia.org/wiki/Uproszczone_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. upr.</a> 土司&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a> <i>tǔsī</i>&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Wade-Giles\" target=\"_blank\" rel=\"noopener noreferrer\">Wade-Giles</a> <i>t’u-ssu</i>) – przywódcy sprawujący władzę w obrębie <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">cesarstwa chińskiego</a> na etnicznie niechińskich terenach, wywodzący się z lokalnych elit ludów podbitych. Stosowany zwłaszcza za czasów dynastii <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Ming\" target=\"_blank\" rel=\"noopener noreferrer\">Ming</a> i <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Qing\" target=\"_blank\" rel=\"noopener noreferrer\">Qing</a> na południowym zachodzie Chin; mianem tym określa się też system takich pośrednich rządów (<b>system tusi</b>, <a href=\"https://pl.wikipedia.org/wiki/Uproszczone_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. upr.</a> 土司制度&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a> <i>tǔsī zhìdù</i>).", "Tomio": "<b>Tomio</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;とみお, トミオ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Teotym": "<b>Teotym</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów <i>theos</i> i <i>tymos</i>, co oznacza \"ten, który czci Boga\" (imię <a href=\"https://pl.wikipedia.org/wiki/Tymoteusz\" target=\"_blank\" rel=\"noopener noreferrer\">Tymoteusz</a> powstało ze złożenia tych samych członów w odwrotnej kolejności). Wśród patronów tego imienia — św. Teotym, biskup <a href=\"https://pl.wikipedia.org/wiki/Konstanca\" target=\"_blank\" rel=\"noopener noreferrer\">Tomi (Konstancy)</a> nad <a href=\"https://pl.wikipedia.org/wiki/Morze_Czarne\" target=\"_blank\" rel=\"noopener noreferrer\">Morzem Czarnym</a>.", "Tarazjusz": "<b>Tarazjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, prawdopodobnie oznaczające \"pochodzący z Tarentum\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Tarazjusz_(patriarcha_Konstantynopola)\" target=\"_blank\" rel=\"noopener noreferrer\">Tarazjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Patriarcha_Konstantynopola\" target=\"_blank\" rel=\"noopener noreferrer\">patriarcha Konstantynopola</a>.", "Toussaint": "Nazwa miejscowości oznacza z francuskiego dosłownie Wszyscy Święci i jest także nazwą <a href=\"https://pl.wikipedia.org/wiki/Uroczysto%C5%9B%C4%87_Wszystkich_%C5%9Awi%C4%99tych\" target=\"_blank\" rel=\"noopener noreferrer\">święta obchodzonego przez chrześcijan 1 listopada</a>.", "Tsukasa": "<b>Tsukasa</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;つかさ, ツカサ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone głównie przez mężczyzn, rzadko przez kobiety.", "Tyburcjusz": "<b>Tyburcjusz</b> lub <b><a href=\"https://pl.wikipedia.org/wiki/Tyburcy\" target=\"_blank\" rel=\"noopener noreferrer\">Tyburcy</a></b>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Tibutius</i> – łacińskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące ze <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnego Rzymu</a>. Wśród patronów <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Tyburcjusz\" target=\"_blank\" rel=\"noopener noreferrer\">św. Tyburcjusz (Tyburcy)</a>, żyjący w <a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wieku</a>.", "Trường Chinh": "Urodził się jako <b>Đặng Xuân Khu</b> w prowincji <a href=\"https://pl.wikipedia.org/wiki/Prowincja_Nam_%C4%90%E1%BB%8Bnh\" target=\"_blank\" rel=\"noopener noreferrer\">Nam Định</a>, w wysoko sytuowanej rodzinie arystokratycznej. Uczył się w prestiżowym Lycée Albert-Sarraut w <a href=\"https://pl.wikipedia.org/wiki/Hanoi\" target=\"_blank\" rel=\"noopener noreferrer\">Hanoi</a>, później przez pewien czas pracował jako nauczyciel. W 1930 roku przystąpił do utworzonej przez <a href=\"https://pl.wikipedia.org/wiki/H%E1%BB%93_Ch%C3%AD_Minh\" target=\"_blank\" rel=\"noopener noreferrer\">Hồ Chí Minha</a> Komunistycznej Partii Indochin. Aresztowany w tym samym roku przez francuskie władze kolonialne, spędził 6 lat w więzieniu Sơn La. Po wyjściu z więzienia poświęcił się działalności politycznej i w 1941 roku został wybrany sekretarzem generalnym Komunistycznej Partii Indochin. Podziwiał przywódcę chińskich komunistów <a href=\"https://pl.wikipedia.org/wiki/Mao_Zedong\" target=\"_blank\" rel=\"noopener noreferrer\">Mao Zedonga</a> i był zwolennikiem stosowania opracowanej przez niego strategii wojny partyzanckiej, a także zmienił swoje imię na <b>Trường Chinh</b>, co po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_wietnamski\" target=\"_blank\" rel=\"noopener noreferrer\">wietnamsku</a> oznacza „<a href=\"https://pl.wikipedia.org/wiki/D%C5%82ugi_Marsz\" target=\"_blank\" rel=\"noopener noreferrer\">Długi Marsz</a>”.", "Tangaroa": "<b>Tangaroa</b>, <b>Takaroa</b> – w mitologii <a href=\"https://pl.wikipedia.org/wiki/Maorysi\" target=\"_blank\" rel=\"noopener noreferrer\">Maorysów</a> <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bóg</a> morza, najstarszy syn Nieba (Vatea) i Ziemi (Papa), brat boga burzy Tawhirimatea. Tangaroa jest ojcem <a href=\"https://pl.wikipedia.org/wiki/Punga\" target=\"_blank\" rel=\"noopener noreferrer\">Punga</a>, który z kolei jest przodkiem wszystkich wodnych stworzeń. W opowieściach maoryskich Tangaroa stoi w opozycji do <a href=\"https://pl.wikipedia.org/wiki/T%C4%81ne\" target=\"_blank\" rel=\"noopener noreferrer\">Tāne</a>, boga lądów, drzew, ptaków i ludzi. Z tego względu rybołówstwo i wyprawy morskie były postrzegane jako wkroczenie na obce terytorium, wymagające uprzedniego złożenia ofiar bogu morza.(Orbell 1998:146–147) Maoryskie podania o Tangaroa posiadają wiele różnych wersji, w innych odmianach występują także wśród innych ludów <a href=\"https://pl.wikipedia.org/wiki/Polinezja\" target=\"_blank\" rel=\"noopener noreferrer\">Polinezji</a>. <a href=\"https://pl.wikipedia.org/wiki/Samoa\" target=\"_blank\" rel=\"noopener noreferrer\">Samoańskim</a> odpowiednikiem Tangaroa jest Tagaloa, na <a href=\"https://pl.wikipedia.org/wiki/Tahiti\" target=\"_blank\" rel=\"noopener noreferrer\">Tahiti</a> nazywany jest Taʻaroa, zaś na <a href=\"https://pl.wikipedia.org/wiki/Hawaje\" target=\"_blank\" rel=\"noopener noreferrer\">Hawajach</a> – Kanaloa, przedstawiany w postaci <i>heʻe</i> (<a href=\"https://pl.wikipedia.org/wiki/Ka%C5%82amarnice\" target=\"_blank\" rel=\"noopener noreferrer\">kałamarnicy</a>).", "Tecumseh": "<b>Tecumseh</b> (<i>Tecumthe</i>, <i>Tikamthe</i>, <i>Tecumtha</i> – w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_algonkia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">j. shawnee</a> imię utożsamiane ze <i>Spadającą Gwiazdą</i> , ur. <a href=\"https://pl.wikipedia.org/wiki/1768\" target=\"_blank\" rel=\"noopener noreferrer\">1768</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/5_pa%C5%BAdziernika\" target=\"_blank\" rel=\"noopener noreferrer\">5 października</a> <a href=\"https://pl.wikipedia.org/wiki/1813\" target=\"_blank\" rel=\"noopener noreferrer\">1813</a>) – wódz <a href=\"https://pl.wikipedia.org/wiki/Indianie_Ameryki_P%C3%B3%C5%82nocnej\" target=\"_blank\" rel=\"noopener noreferrer\">północnoamerykańskiego plemienia indiańskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Szaunisi\" target=\"_blank\" rel=\"noopener noreferrer\">Szaunisów</a> (Szawanezów), przywódca wojskowy, mówca, polityk, generał brytyjski. Na początku <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX w.</a> był zwolennikiem utworzenia szerokiej konfederacji plemion indiańskich na południe od <a href=\"https://pl.wikipedia.org/wiki/Wielkie_Jeziora\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkich Jezior</a>, której celem byłoby powstrzymanie inwazji białych. Zgodnie z biografią autorstwa Johna Sugdena jego ojcem był <b>Pukeshinwau</b> (<i>Lecąc Płonie</i>), wódz wojenny szauniskiej grupy Kispoko z klanu Pantery, matką pochodząca z narodu Krików <b>Methoataaskee</b> (<i>Żółwica Składająca Jaja</i>). Rodzeństwo wg kolejności urodzeń: najstarszy brat <b>Cheeseekau</b>, siostra <b>Tecumapease</b> (<i>Lecąca Nad Wodą</i>), brat <b>Sauaweseekau</b> (<i>Skacząca Pantera</i>), oraz młodszy brat Laloeshiga, znany później jako <b>Tenskwatawa</b> (<i>Otwarte Drzwi</i>). Imię Tecumseha w uproszczeniu oznacza <i>Spadającą z Nieba Gwiazdę</i> i wiąże się z lecącym meteorytem w dniu jego narodzin, jednak biorąc pod uwagę barwne indiańskie określenia znaczy dokładnie \"gwiaździstą istotę zlatującą z nieba\". Ponieważ Tecumseh należał do klanu Pantery, jego imię Szaunisi utożsamiali z \"panterą (pumą) spadającą z nieba na ofiarę\", z czego Amerykanie ukuli <i>Skaczącą Pumę.</i> Tymczasem inne wyjaśnienie znajdziemy w portalu <i>Ohio History Connection</i>, gdzie określenie Tecumseh właściwie oznacza \"tego, który przechodzi\" w rozumieniu z jednego punktu do drugiego, przy czym imię wskazuje, że jego właściciel należy do klanu mistycznej Wielkiej Pantery siedzącej na nieboskłonie (jako gwiazda lub spadający meteoryt), stąd interpretacja <i>Spadająca Gwiazda</i> lub <i>Skacząca (Przyczajona) Pantera</i><i>.</i>", "Topaz": "Nazwa pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> τοπάζιος (<i>topázios, topazos</i>) oznaczającego <i>poszukiwać</i> i <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> topasus, które są związane prawdopodobnie ze starą sanskrycką nazwą topas oznaczającą ogień, co nawiązuje do pomarańczowo-złotej barwy i blasku szlachetnych odmian tego minerału. Niektórzy wywodzą nazwę topaz od wyspy Topasios (obecnie należącej do <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egiptu</a>), położonej na <a href=\"https://pl.wikipedia.org/wiki/Morze_Czerwone\" target=\"_blank\" rel=\"noopener noreferrer\">Morzu Czerwonym</a>.", "Tęgomir": "<b>Tęgomir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członu <i>Tęgo-</i> („mocny”) <i>-mir</i> („pokój, spokój, dobro”). Może zatem oznaczać „trwały, stabilny pokój”.", "Tamara": "<b>Tamara</b> – współczesna forma żeńskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a> <b>Tamar</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aram.</a>&#160;&#8207;ܬܡܪ&#8206; – <i><a href=\"https://pl.wikipedia.org/wiki/Daktylowiec_w%C5%82a%C5%9Bciwy\" target=\"_blank\" rel=\"noopener noreferrer\">palma daktylowa</a></i>).", "Tathagata": "<b>Tathagata</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">skt.</a> tathāgata तथागत) — jedno z określeń <a href=\"https://pl.wikipedia.org/wiki/Budda_Siakjamuni\" target=\"_blank\" rel=\"noopener noreferrer\">Buddy</a>. Dość powszechnie mówi się, że <i>tathagata</i> znaczy \"ten, który przyniósł prawdę\", \"ten, który osiągnął prawdziwe wyzwolenie\". Jednakże znaczenie tego słowa nie jest jasne, przede wszystkim dlatego, że nie występuje we wszystkich tekstach <a href=\"https://pl.wikipedia.org/wiki/Kanon_palijski\" target=\"_blank\" rel=\"noopener noreferrer\">kanonu palijskiego</a>, a tam gdzie występuje jest używane w różnych kontekstach. Np. gdy Budda mówi o sobie w trzeciej osobie, określa siebie właśnie jako <b>tathagatę</b>, ale w odniesieniu do <a href=\"https://pl.wikipedia.org/wiki/Arhat\" target=\"_blank\" rel=\"noopener noreferrer\">arhatów</a> również używa tego określenia.", "Tajfun": "Słowo „tajfun” <a href=\"https://pl.wikipedia.org/wiki/Sinicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">wywodzi się z chińskiego</a> 台风 (<i>táifēng</i>) i oznacza „wiatr z <a href=\"https://pl.wikipedia.org/wiki/Tajwan_(wyspa)\" target=\"_blank\" rel=\"noopener noreferrer\">Tajwanu</a>”.", "Tatiana": "<b>Tacjana</b>, <i><b>Tacjanna</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia rzymskiego; żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Tacjan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tacjan</a> utworzonego z rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Tatianus</i>, który powstał z nazwy rzymskiego rodu <i>Tatius</i> (pol. Tacjusz) poprzez dodanie przyrostka <i>-anus/ana</i> oznaczającego przynależność, pochodzenie. Imię to było notowane w Polsce od średniowiecza na obszarze wschodniosłowiańskim, po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/1411\" target=\"_blank\" rel=\"noopener noreferrer\">1411</a> roku, w formach <i><b>Tacyjana</b></i>, <i><b>Tatyjana</b></i>, <i><b>Tetejana</b></i>, <i><b>Tetyjana</b></i>, <i><b>Tatyjanna</b></i>, ze zdrobnieniami Tatja, Tac(z)a, Tańka = Tajka.", "Tane": "<b>Tāne</b>, <b>Tāne Mahuta</b> – <a href=\"https://pl.wikipedia.org/wiki/Maorysi\" target=\"_blank\" rel=\"noopener noreferrer\">maoryski</a> <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bóg</a> <a href=\"https://pl.wikipedia.org/wiki/Las\" target=\"_blank\" rel=\"noopener noreferrer\">lasów</a>. W <a href=\"https://pl.wikipedia.org/wiki/Mitologia\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii</a> maoryskiej jest on synem <a href=\"https://pl.wikipedia.org/wiki/Rangi\" target=\"_blank\" rel=\"noopener noreferrer\">Rangi</a> (boga nieba) i Papatuanuku (<a href=\"https://pl.wikipedia.org/wiki/Bogini\" target=\"_blank\" rel=\"noopener noreferrer\">bogini</a> ziemi). Na <a href=\"https://pl.wikipedia.org/wiki/Hawaje\" target=\"_blank\" rel=\"noopener noreferrer\">Hawajach</a> jego odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/K%C4%81ne\" target=\"_blank\" rel=\"noopener noreferrer\">Kāne</a>. Uważany jest za praojca drzew, ptaków i ludzi. Stworzył pierwszego człowieka, w mitologiach <a href=\"https://pl.wikipedia.org/wiki/Polinezja\" target=\"_blank\" rel=\"noopener noreferrer\">Polinezji</a> określanego jako <a href=\"https://pl.wikipedia.org/wiki/Tiki\" target=\"_blank\" rel=\"noopener noreferrer\">Tiki</a>. Budowniczowie łodzi wznosili pieśni do Tāne, aby pobłogosławił ich pracę oraz uczynił łodzie odpornymi na fale wywoływane przez <a href=\"https://pl.wikipedia.org/wiki/Tangaroa\" target=\"_blank\" rel=\"noopener noreferrer\">Tangaroa</a>.", "Taira": "<b>Taira</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;平氏&#32;<i>Heishi, Taira-uji</i>) – <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">ród</a> japoński władający <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonią</a> od 1161 do 1185, wywodzący swoje pochodzenie od <a href=\"https://pl.wikipedia.org/wiki/Kammu\" target=\"_blank\" rel=\"noopener noreferrer\">cesarza Kammu</a>. Nazywany również Heike&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;平家) zgodnie z sinojapońską wymową znaków.", "Tercjusz": "<b>Tercjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od liczebnika oznaczającego \"trzeci\" (por. <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiusz</a>). Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Tercjusz_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Tercjusz</a>, wspominany razem ze śwśw. Dionizją, Datywą, Leoncją, Emilianem, Bonifacym, Majorykiem i Serwusem (V wiek).", "Teonas": "<b>Teonas</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> Θεωνάς, Theónas, oznaczające \"boski\" lub, według innych źródeł, dotyczącego osoby wywodzącej się z <a href=\"https://pl.wikipedia.org/wiki/Teos\" target=\"_blank\" rel=\"noopener noreferrer\">Teos</a>, miasta w <a href=\"https://pl.wikipedia.org/wiki/Jonia\" target=\"_blank\" rel=\"noopener noreferrer\">Jonii</a>.", "Toligniew": "<b>Toligniew</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Składa się z członów <i>Toli-</i> (<i>toliti</i> – \"uspokajać\", też: \"tulić, obejmować rękami\"), i <i>-gniew</i> (\"gniew\"). Znaczenie imienia: \"ten, który uspokaja gniew\".", "Tank": "Polska nazwa „czołg” pochodzi od sposobu poruszania pierwszych maszyn, które zdawały się powoli czołgać po ziemi na swoich gąsienicach. Nazwę tę zaproponował por. <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adys%C5%82aw_Kohutnicki\" target=\"_blank\" rel=\"noopener noreferrer\">Władysław Kohutnicki</a> w 1919 roku.", "Tauhid": "Tauhid oznacza istnienie Boga oraz jego jedyność, wyłączność stwarzania, kierowania i pełnię władzy. Bóg jest stwórcą, przyczyną dobrobytu i tym, który wszystkim kieruje. Tauhid oznacza też wspólne pochodzenie i równość ludzi we wszystkich aspektach życia. Ponieważ Bóg uczynił człowieka swoim następcą na Ziemi, człowiek ma rządzić zgodnie z jego nakazami zachowując posłuszeństwo jego woli.", "Tylon": "Tylon pochodził z rodziny mieszczańskiej. Jego rodzonymi braćmi byli inni pisarze Przemysła: Jaśko, Mikołaj (późniejszy <a href=\"https://pl.wikipedia.org/wiki/Kanonik\" target=\"_blank\" rel=\"noopener noreferrer\">kanonik</a> poznański), Jakub (kanonik oraz notariusz <a href=\"https://pl.wikipedia.org/wiki/Biskupi_pozna%C5%84scy\" target=\"_blank\" rel=\"noopener noreferrer\">biskupa poznańskiego</a>). Mieli oni jeszcze piątego brata Stefana, który był również kanonikiem poznańskim.", "Teresa": "<b>Teresa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Może wywodzić się od słowa oznaczającego „mieszkanka wyspy Thera (<i>znanej dziś jako: <a href=\"https://pl.wikipedia.org/wiki/Santoryn\" target=\"_blank\" rel=\"noopener noreferrer\">Santoryn</a></i>)”.", "Tygriusz": "<b>Tygriusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> od nazwy <i>tigris</i>, <i>–idis</i> — \"tygrys, tygrysica\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Tygriusz_i_Eutropiusz\" target=\"_blank\" rel=\"noopener noreferrer\">św. Tygriusz</a>, kapłan, wspominany razem ze <a href=\"https://pl.wikipedia.org/wiki/Tygriusz_i_Eutropiusz\" target=\"_blank\" rel=\"noopener noreferrer\">św. Eutropiuszem</a>.", "Theoden": "Według fikcyjnej etymologii Tolkiena imię Théoden jest przekładem z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rohirricki\" target=\"_blank\" rel=\"noopener noreferrer\">języka Rohirrimów</a>, w którym brzmiało ono Tûrac. Faktycznie pochodzi ono od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">anglosaskiego</a> słowa <i>þeoden</i>, oznaczającego władcę.", "Tymotka": "<b>Tymotka</b> (<i>Phleum</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/Wiechlinowate\" target=\"_blank\" rel=\"noopener noreferrer\">wiechlinowatych</a>. Obejmuje 15 gatunków występujących w <a href=\"https://pl.wikipedia.org/wiki/Strefy_umiarkowane\" target=\"_blank\" rel=\"noopener noreferrer\">strefie umiarkowanej</a> półkuli północnej oraz w <a href=\"https://pl.wikipedia.org/wiki/Ameryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryce Południowej</a>. Kilka gatunków ma istotne znaczenie jako <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny_pastewne\" target=\"_blank\" rel=\"noopener noreferrer\">rośliny pastewne</a>, zwłaszcza <a href=\"https://pl.wikipedia.org/wiki/Tymotka_%C5%82%C4%85kowa\" target=\"_blank\" rel=\"noopener noreferrer\">tymotka łąkowa</a> <i>Phleum pratense</i>. Trawy te są częstym powodem <a href=\"https://pl.wikipedia.org/wiki/Katar_sienny\" target=\"_blank\" rel=\"noopener noreferrer\">kataru siennego</a>. Wszystkie posiadają zbity, cylindryczny <a href=\"https://pl.wikipedia.org/wiki/Kwiatostan\" target=\"_blank\" rel=\"noopener noreferrer\">kwiatostan</a>.", "Teodora": "<b>Teodora</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a>. To samo znaczenie ma złożone z analogicznych członów, tylko w odwrotnej kolejności, imię <a href=\"https://pl.wikipedia.org/wiki/Dorota\" target=\"_blank\" rel=\"noopener noreferrer\">Dorota</a>.", "Teodozja": "<b>Teodozja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Teodozy\" target=\"_blank\" rel=\"noopener noreferrer\">Teodozy</a>. Oznacza „dana od Boga”. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Teodozja_z_Cezarei\" target=\"_blank\" rel=\"noopener noreferrer\">Teodozja z Cezarei</a> (†307), męczennica.", "Teofila": "<b>Teofila</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Teofil\" target=\"_blank\" rel=\"noopener noreferrer\">Teofil</a>. Oznacza „miłującą Boga”. Za odpowiedniki znaczeniowe uznaje się m.in. imiona <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">Bogumiła</a> i <a href=\"https://pl.wikipedia.org/wiki/Amadea\" target=\"_blank\" rel=\"noopener noreferrer\">Amadea</a>.", "Tekla": "<b>Tekla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „sławiąca Boga” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Θεός „Bóg” i κλέος „sława”).", "Taisa": "<b>Taida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> od egipskiego imienia <i>Thaisis</i> (bogini <a href=\"https://pl.wikipedia.org/wiki/Izyda\" target=\"_blank\" rel=\"noopener noreferrer\">Izyda</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a> <i>Isis</i>, <i>Isidos</i>). Imię to, w formie gr. <i>Thais</i> lub <i>Thaida</i>, nosiła kochanka <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Wielkiego</a>. Znana jest również opera <a href=\"https://pl.wikipedia.org/wiki/Tha%C3%AFs_(opera)\" target=\"_blank\" rel=\"noopener noreferrer\">Thaïs</a> <a href=\"https://pl.wikipedia.org/wiki/Jules_Massenet\" target=\"_blank\" rel=\"noopener noreferrer\">Masseneta</a>.", "Tina": "<b>Tina</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, powstałe jako zdrobnienie od imion takich, jak <a href=\"https://pl.wikipedia.org/wiki/Krystyna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Krystyna</a>, <a href=\"https://pl.wikipedia.org/wiki/Martyna\" target=\"_blank\" rel=\"noopener noreferrer\">Martyna</a>, <a href=\"https://pl.wikipedia.org/wiki/Justyna\" target=\"_blank\" rel=\"noopener noreferrer\">Justyna</a>, <a href=\"https://pl.wikipedia.org/wiki/Florentyna\" target=\"_blank\" rel=\"noopener noreferrer\">Florentyna</a>, <a href=\"https://pl.wikipedia.org/wiki/Walentyna\" target=\"_blank\" rel=\"noopener noreferrer\">Walentyna</a>, <a href=\"https://pl.wikipedia.org/wiki/Augustyna\" target=\"_blank\" rel=\"noopener noreferrer\">Augustyna</a> czy <a href=\"https://pl.wikipedia.org/wiki/Klementyna\" target=\"_blank\" rel=\"noopener noreferrer\">Klementyna</a>. W Polsce imię to jest odradzane przez <a href=\"https://pl.wikipedia.org/wiki/Rada_J%C4%99zyka_Polskiego\" target=\"_blank\" rel=\"noopener noreferrer\">Radę Języka Polskiego</a>.", "Teona": "<b>Teona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Teonas\" target=\"_blank\" rel=\"noopener noreferrer\">Teonas</a>, oznaczającego \"boski\" lub, według innych źródeł, dotyczącego osoby wywodzącej się z <a href=\"https://pl.wikipedia.org/wiki/Teos\" target=\"_blank\" rel=\"noopener noreferrer\">Teos</a>, miasta w <a href=\"https://pl.wikipedia.org/wiki/Jonia\" target=\"_blank\" rel=\"noopener noreferrer\">Jonii</a>.", "Telimena": "<b>Telimena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o nieustalonej etymologii. Być może powstało poprzez przekształcenie <a href=\"https://pl.wikipedia.org/wiki/Filomena\" target=\"_blank\" rel=\"noopener noreferrer\">Filomeny</a> na gruncie języka białoruskiego. W literaturze pojawiło się na początku <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Tomira": "<b>Tomira</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnym pochodzeniu. Najprawdopodobniej powstało na gruncie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">języka serbsko-chorwackiego</a> (w źródłach serbsko-chorwackich pojawia się od <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>) i stanowiło skróconą formę imienia <i>Tomimira</i> (czyli <i>tomiti</i> – „dręczyć, męczyć”, por. <a href=\"https://pl.wikipedia.org/wiki/Tomis%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tomisław</a>, i <i>-mira</i>). Istnieje także możliwość, że Tomira powstała jako zdrobnienie innych imion, np. <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99tomira\" target=\"_blank\" rel=\"noopener noreferrer\">Świętomiry</a>.", "Tacjana": "<b>Tacjana</b>, <i><b>Tacjanna</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia rzymskiego; żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Tacjan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tacjan</a> utworzonego z rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Tatianus</i>, który powstał z nazwy rzymskiego rodu <i>Tatius</i> (pol. Tacjusz) poprzez dodanie przyrostka <i>-anus/ana</i> oznaczającego przynależność, pochodzenie. Imię to było notowane w Polsce od średniowiecza na obszarze wschodniosłowiańskim, po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/1411\" target=\"_blank\" rel=\"noopener noreferrer\">1411</a> roku, w formach <i><b>Tacyjana</b></i>, <i><b>Tatyjana</b></i>, <i><b>Tetejana</b></i>, <i><b>Tetyjana</b></i>, <i><b>Tatyjanna</b></i>, ze zdrobnieniami Tatja, Tac(z)a, Tańka = Tajka.", "Tarsylia": "<b>Tarsylia</b>, <b>Tarsylla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"kobietę pochodzącą z Tarsu\". Patronka tego imienia – <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Tarzylla\" target=\"_blank\" rel=\"noopener noreferrer\">św. Tarsylia</a>, była ciotką <a href=\"https://pl.wikipedia.org/wiki/Grzegorz_I\" target=\"_blank\" rel=\"noopener noreferrer\">papieża Grzegorza Wielkiego</a>.", "Tulia": "<b>Tulia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od rzymskiej nazwy rodowej prawdopodobnie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_etruski\" target=\"_blank\" rel=\"noopener noreferrer\">etruskiego</a>. Patronką tego imienia jest św. Tulia, siostra św. Konsorcji, obie miały być córkami św. <a href=\"https://pl.wikipedia.org/wiki/Eucheriusz_z_Lyonu\" target=\"_blank\" rel=\"noopener noreferrer\">Eucheriusza</a> z <a href=\"https://pl.wikipedia.org/wiki/Lyon\" target=\"_blank\" rel=\"noopener noreferrer\">Lyonu</a>. Jedną z bardziej znanych postaci o tym imieniu była Tullia, córka <a href=\"https://pl.wikipedia.org/wiki/Cyceron\" target=\"_blank\" rel=\"noopener noreferrer\">Marka Tuliusza Cycerona</a>.", "Tala": "<b>Tala</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, którego patronem jest św. Talus, wspominany razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Trofim\" target=\"_blank\" rel=\"noopener noreferrer\">Trofimem</a>, zm. w <a href=\"https://pl.wikipedia.org/wiki/308\" target=\"_blank\" rel=\"noopener noreferrer\">308</a> roku.", "Talita": "<b>Talita</b> (<i>ταλιθα</i>, <i>Talitha</i>): <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Źródłem jest <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskie</a> słowo \"'ţlîthâ'\" – “dziewczyna”. Pochodzi od wypowiedzi <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa</a>: \"Talitha cum(i)!\" (spolszczonej na: \"Talita kum!\") – \"Dziewczynko, tobie mówię, wstań\" – użytej podczas <a href=\"https://pl.wikipedia.org/wiki/Zmartwychwstanie\" target=\"_blank\" rel=\"noopener noreferrer\">wskrzeszenia</a> córki Jaira.", "Tolisława": "<b>Tolisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Składa się z członów <i>Toli-</i> (<i>toliti</i> – \"uspokajać\", też: \"tulić\"), i <i>-sława</i> (\"sława\"). Znaczenie imienia: \"wyciszająca sławę\", \"skromna\". Męski odpowiednik – <a href=\"https://pl.wikipedia.org/wiki/Tolis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Tolisław</a>. W źródłach polskich poświadczone w XIV wieku (1333 rok).", "Tycjana": "<b>Tycjana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od nazwy rodowej <i>Titianus</i>, co oznacza \"pochodząca od <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytusa</a>\", \"należąca do Tytusa\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Tycjan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tycjan</a>. Wśród patronów - św. Tycjan, biskup (zm. w <a href=\"https://pl.wikipedia.org/wiki/650\" target=\"_blank\" rel=\"noopener noreferrer\">650</a> roku).", "Tomiła": "<b>Tomiła</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>To-</i> i <i>-miła</i>. Męski odpowiednik: <a href=\"https://pl.wikipedia.org/wiki/Tomi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Tomił</a>.", "Tabita": "<b>Tabita</b> (od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> „tabitha” – „gazela”) – semickie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Pochodzi od postaci pobożnej chrześcijanki, wskrzeszonej przez <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Piotra Apostoła</a> (po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecku</a> zwana <i>Dorkas</i>). W <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> Tabita pojawia się w <a href=\"https://pl.wikipedia.org/wiki/Dzieje_Apostolskie\" target=\"_blank\" rel=\"noopener noreferrer\">Dziejach Apostolskich</a>.", "Tomoko": "<b>Tomoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ともこ, トモコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Tadea": "<b>Tadea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Tadeusz\" target=\"_blank\" rel=\"noopener noreferrer\">Tadeusz</a>, którego pochodzenie jest prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskie</a> (i ma związek z aramejskim <i>thad-daj</i> – „człowiek o szerokiej piersi”), lub też <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskie</a> (i wywodzi się od <i>taddai</i>, czyli „sprytny, mądry”). Imię Tadea jest notowane w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1738\" target=\"_blank\" rel=\"noopener noreferrer\">1738</a> roku.", "Tacjanna": "<b>Tacjana</b>, <i><b>Tacjanna</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia rzymskiego; żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Tacjan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tacjan</a> utworzonego z rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Tatianus</i>, który powstał z nazwy rzymskiego rodu <i>Tatius</i> (pol. Tacjusz) poprzez dodanie przyrostka <i>-anus/ana</i> oznaczającego przynależność, pochodzenie. Imię to było notowane w Polsce od średniowiecza na obszarze wschodniosłowiańskim, po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/1411\" target=\"_blank\" rel=\"noopener noreferrer\">1411</a> roku, w formach <i><b>Tacyjana</b></i>, <i><b>Tatyjana</b></i>, <i><b>Tetejana</b></i>, <i><b>Tetyjana</b></i>, <i><b>Tatyjanna</b></i>, ze zdrobnieniami Tatja, Tac(z)a, Tańka = Tajka.", "Tomisława": "<b>Tomisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Tomi-</i> (<i>tomiti</i> – \"dręczyć, męczyć\") i <i>-sław</i> (\"sława\"). Mogło oznaczać \"tę, którą dręczy potrzeba sławy\". Męski odpowiednik: <a href=\"https://pl.wikipedia.org/wiki/Tomis%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tomisław</a>. W źródłach polskich poświadczone od XIV wieku (1386 rok).", "Tabea": "<b>Tabita</b> (od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a> „tabitha” – „gazela”) – semickie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Pochodzi od postaci pobożnej chrześcijanki, wskrzeszonej przez <a href=\"https://pl.wikipedia.org/wiki/Piotr_Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Piotra Apostoła</a> (po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecku</a> zwana <i>Dorkas</i>). W <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> Tabita pojawia się w <a href=\"https://pl.wikipedia.org/wiki/Dzieje_Apostolskie\" target=\"_blank\" rel=\"noopener noreferrer\">Dziejach Apostolskich</a>.", "Telesfora": "<b>Telesfora</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Telesfor\" target=\"_blank\" rel=\"noopener noreferrer\">Telesfor</a>, oznaczającego „doprowadzony do końca, doprowadzony do doskonałości”.", "Tamia": "<b>Tamia</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/9_maja\" target=\"_blank\" rel=\"noopener noreferrer\">9 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1975\" target=\"_blank\" rel=\"noopener noreferrer\">1975</a> w <a href=\"https://pl.wikipedia.org/wiki/Windsor_(Ontario)\" target=\"_blank\" rel=\"noopener noreferrer\">Windsorze</a> w stanie <a href=\"https://pl.wikipedia.org/wiki/Ontario\" target=\"_blank\" rel=\"noopener noreferrer\">Ontario</a>) – <a href=\"https://pl.wikipedia.org/wiki/Kanada\" target=\"_blank\" rel=\"noopener noreferrer\">kanadyjska</a> <a href=\"https://pl.wikipedia.org/wiki/Piosenkarz\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarka</a> i <a href=\"https://pl.wikipedia.org/wiki/Aktor\" target=\"_blank\" rel=\"noopener noreferrer\">aktorka</a>. Sześciokrotnie nomiowana do <a href=\"https://pl.wikipedia.org/wiki/Nagroda_Grammy\" target=\"_blank\" rel=\"noopener noreferrer\">Nagrody Grammy</a> w <a href=\"https://pl.wikipedia.org/wiki/Lista_kategorii_nagr%C3%B3d_Grammy\" target=\"_blank\" rel=\"noopener noreferrer\">kategorii najlepsza piosenkarka R&amp;B</a>. Jej największym hitem jest <i>Stranger in My House</i> pochodzący z albumu <i>A Nu Day</i> (2000 rok).", "Tora": "W szerszym znaczeniu – cała <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Biblia hebrajska</a> (Tora pisana, <i><a href=\"https://pl.wikipedia.org/wiki/Tanach\" target=\"_blank\" rel=\"noopener noreferrer\">Tanach</a></i>) oraz tradycja teologiczno-prawna judaizmu (Tora ustna).", "Teta": "<b>Theta</b> (<b>thita</b>, <b>θῆτα</b>, pisana <b>Θθ</b> lub <b>ϴϑ</b>) – ósma <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a> oznaczająca <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_przydechowa\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę aspirowaną</a> „t” (czyli „th”). W greckim systemie liczbowym oznacza <a href=\"https://pl.wikipedia.org/wiki/Liczba\" target=\"_blank\" rel=\"noopener noreferrer\">liczbę</a> <a href=\"https://pl.wikipedia.org/wiki/9_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">9</a>.", "Thuraya": "<b>Telefonia Thuraya</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;الثريا&#8206;, co oznacza „plejady”) – regionalny operator telefonii satelitarnej. Zasięg sieci obejmuje większość Europy, Bliski Wschód, Afrykę Północną, Środkową i Wschodnią, Azję i Australię.", "Toshiko": "<b>Toshiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;としこ, トシコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Tosława": "<b>Stojsława</b>, <b>Stoisława</b>, <b>Tosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Stoj(i)-</i> (\"stać, stoję\") oraz członu <i>-sława</i> (\"sława\"). Oznacza \"ta, która ma stać się sławną\". Męskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Stojs%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stojsław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stojs%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stoisław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stojs%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stojs%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Tosław</a>. W źródłach polskich poświadczone w XV wieku (1439 rok).", "T": "<b>T</b> (<i>te</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>t</b>) – dwudziesta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, dwudziesta szósta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Oznacza zwykle w danym języku spółgłoskę przedniojęzykową zwartą bezdźwięczną, np. [k", "Triada": "Triada z <a href=\"https://pl.wikipedia.org/wiki/Hongkong\" target=\"_blank\" rel=\"noopener noreferrer\">Hongkongu</a> różni się od organizacji przestępczych z Chin kontynentalnych. W starożytnych Chinach triada była jednym z trzech głównych tajnych stowarzyszeń. Tworzyła oddziały w Makau, Hongkongu, Tajwanie i chińskich społecznościach za granicą. Znane jako „organizacje przestępcze z Chin kontynentalnych” dzielą się na dwa główne typy: ciemne siły (luźno zorganizowane grupy) i czarne społeczeństwa (dojrzalsze organizacje przestępcze). Dwie cechy, które odróżniają czarne społeczeństwo od ciemnej siły, to zdolność do uzyskania nielegalnej kontroli nad lokalnymi rynkami i otrzymywania ochrony policyjnej. Triada hongkońska odnosi się do tradycyjnych organizacji przestępczych działających w (lub pochodzących z) Hongkongu, <a href=\"https://pl.wikipedia.org/wiki/Makau\" target=\"_blank\" rel=\"noopener noreferrer\">Makau</a>, <a href=\"https://pl.wikipedia.org/wiki/Tajwan_(wyspa)\" target=\"_blank\" rel=\"noopener noreferrer\">Tajwanu</a> oraz krajów i regionów <a href=\"https://pl.wikipedia.org/wiki/Azja_Po%C5%82udniowo-Wschodnia\" target=\"_blank\" rel=\"noopener noreferrer\">Azji Południowo-Wschodniej</a>, podczas gdy zorganizowane grupy przestępcze w Chinach kontynentalnych znane są jako „chińskie grupy przestępcze z Chin kontynentalnych”.", "Tymona": "<b>Tymona</b>&#8201; – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Tymon\" target=\"_blank\" rel=\"noopener noreferrer\">Tymon</a>, utworzonego od greckich imion złożonych typu <a href=\"https://pl.wikipedia.org/wiki/Tymoteusz\" target=\"_blank\" rel=\"noopener noreferrer\">Tymoteusz</a> — po odrzuceniu drugiego członu imienia — za pomocą <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-ōn</i>. W dawnych źródłach polskich (od <a href=\"https://pl.wikipedia.org/wiki/1492\" target=\"_blank\" rel=\"noopener noreferrer\">1492</a> roku) występowała w Polsce <i><b>Tymka</b></i>, a także wschodniosłowiańskiego Tyszka (od <a href=\"https://pl.wikipedia.org/wiki/1388\" target=\"_blank\" rel=\"noopener noreferrer\">1388</a> r.&#8201;), utworzona od pierwszego członu imienia <a href=\"https://pl.wikipedia.org/wiki/Tymoteusz\" target=\"_blank\" rel=\"noopener noreferrer\">Tymoteusz</a>&#8201;.", "Toja": "<b>Toina</b> (<i>Apocynum</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/Toinowate\" target=\"_blank\" rel=\"noopener noreferrer\">toinowatych</a> (<i>Apocynaceae</i>). Rodzaj liczy 4 gatunki. Występują one w strefie umiarkowanej <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a>, <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">Azji</a> i południowo-wschodniej <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europy</a>. Znaczenie użytkowe ma toina konopiowata <i>A. cannabinum</i> uprawiana w USA jako roślina lecznicza, włóknista i przemysłowa. W literaturze rzadko pojawia się nazwa „kandyr” lub „konopie kalifornijskie”.", "Triola": "W nutach są różne sposoby zapisywania trioli, aczkolwiek najczęściej triola oznaczana jest cyfrą 3 umieszczaną nad lub pod grupą. W zależności od wartości rytmicznych, jakie wchodzą w skład trójki, występuje triola <a href=\"https://pl.wikipedia.org/wiki/%C4%86wier%C4%87nuta\" target=\"_blank\" rel=\"noopener noreferrer\">ćwierćnutowa</a>, <a href=\"https://pl.wikipedia.org/wiki/%C3%93semka_(nuta)\" target=\"_blank\" rel=\"noopener noreferrer\">ósemkowa</a>, <a href=\"https://pl.wikipedia.org/wiki/Szesnastka\" target=\"_blank\" rel=\"noopener noreferrer\">szesnastkowa</a>, itd.", "Tarika": "Początki ruchu mistycznego w świecie islamu związane są z samotnymi jednostkami, poszukującymi Boga na własną rękę, jednak stosunkowo szybko zaczęły one współpracować ze sobą i gromadzić się w celu dzielenia się swoimi doświadczeniami i wspólnego dążenia do celu. Prawdziwa instytucjonalizacja ruchu sufickiego nastąpiła jednak dopiero w wieku XI, wtedy też nazwa tarika, która dotychczas była odnoszona do sposobu postępowania, praktykowanego lub zalecanego przez pojedynczego sufiego, zaczęła oznaczać regułę bractwa sufickiego lub samo bractwo.", "Teobalda": "<b>Teobalda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia germańskiego; utworzone od słów: <i>þeudo</i> (germ.), <i>diet</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">śrwniem.</a>) — „lud” i <i>bald</i> — „odważny, śmiały”. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Teobald\" target=\"_blank\" rel=\"noopener noreferrer\">Teobald</a>. Wśród patronów - m.in. św. Teobald, prezbiter i pustelnik (<a href=\"https://pl.wikipedia.org/wiki/XI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XI wiek</a>).", "Taqwa": "<b>Taqwa</b> lub <b>Taqła</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;تقوى, taqwā / taqwá&#8206;) – islamski termin oznaczający <a href=\"https://pl.wikipedia.org/wiki/Pobo%C5%BCno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">pobożność</a>, świadomość o Bogu, powściągliwość i bogobojność."};
